mapper.select:
SELECT id, source_id, target_id, relation_type, status, group_id, create_time
FROM user_relation
WHERE source_id = #{sourceId} AND target_id = #{targetId} AND relation_type = #{relationType}

SELECT id, source_id, target_id, relation_type, status, group_id, create_time
FROM user_relation
WHERE source_id = #{sourceId}

    AND relation_type = #{relationType}

SELECT COUNT(1)
FROM user_relation
WHERE source_id = #{sourceId}

    AND relation_type = #{relationType}

SELECT COUNT(1)
FROM user_relation
WHERE source_id = #{sourceId}
  AND relation_type = #{relationType}
  AND status = #{status}

SELECT id, source_id, target_id, relation_type, status, group_id, create_time
FROM user_relation
WHERE target_id = #{targetId}

    AND relation_type = #{relationType}

SELECT COUNT(1)
FROM user_relation
WHERE target_id = #{targetId}

    AND relation_type = #{relationType}

SELECT COUNT(1)
FROM user_relation
WHERE target_id = #{targetId}
  AND relation_type = #{relationType}
  AND status = #{status}

SELECT r.target_id
FROM user_relation r
WHERE r.source_id = #{sourceId}
  AND r.relation_type = #{relationType}
  AND r.status = #{status}
  AND (SELECT COUNT(1) FROM user_follower uf WHERE uf.user_id = r.target_id) >= #{followerThreshold}
LIMIT #{limit}

SELECT id, source_id, target_id, relation_type, status, group_id, create_time
FROM user_relation
WHERE source_id = #{sourceId}
  AND relation_type = #{relationType}
  AND status = #{status}

      AND (
          create_time < #{cursorTime}
          OR (create_time = #{cursorTime} AND target_id < #{cursorTargetId})
      )

ORDER BY create_time DESC, target_id DESC
LIMIT #{limit}

SELECT id, source_id, target_id, relation_type, status, group_id, create_time
FROM user_relation
WHERE target_id = #{targetId}
  AND relation_type = #{relationType}
  AND status = #{status}

      AND (
          create_time < #{cursorTime}
          OR (create_time = #{cursorTime} AND source_id < #{cursorSourceId})
      )

ORDER BY create_time DESC, source_id DESC
LIMIT #{limit}
